import React from 'react'
import useToastStore from './useToastStore'
function useToast() {
    const open = useToastStore((state) => state.openToast)
    const close = useToastStore((state) => state.closeToast)

    const openToast = ({ message, type }) => {
        const id = `modal_${idx++}`
        open({ message, type, id })
    }

    const closeToast = ({ id }) => {
        close(id)
    }
    return { openToast, closeToast }
}

export default useToast
